CREATE TABLE `job_card_items` (
  `id` int NOT NULL AUTO_INCREMENT,
  `job_card_no` varchar(50) NOT NULL,
  `item_name` varchar(500) NOT NULL,
  `material` varchar(255) DEFAULT NULL,
  `size` varchar(100) DEFAULT NULL,
  `so_qty` int DEFAULT NULL,
  `job_card_qty` int DEFAULT NULL,
  `advance_stock` varchar(100) DEFAULT NULL,
  `actual_qty` int DEFAULT '0',
  `wip_status` varchar(100) DEFAULT 'Pending',
  `wip_stage_days` int DEFAULT '0',
  `total_days` int DEFAULT '0',
  `delivery_date` date DEFAULT NULL,
  `remarks` varchar(500) DEFAULT NULL,
  `remaining_days` int DEFAULT '0',
  `part` varchar(255) DEFAULT NULL,
  `dia` varchar(50) DEFAULT NULL,
  `length` varchar(50) DEFAULT NULL,
  `rejected_qty` int DEFAULT '0',
  `revoked_qty` int DEFAULT '0',
  `merged_qty` int DEFAULT '0',
  `rework_qty` int DEFAULT '0',
  `is_priority` tinyint(1) DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `idx_wip_status` (`wip_status`),
  KEY `idx_delivery_date` (`delivery_date`),
  KEY `idx_item_name` (`item_name`(100)),
  KEY `idx_jc_no` (`job_card_no`),
  CONSTRAINT `job_card_items_ibfk_1` FOREIGN KEY (`job_card_no`) REFERENCES `job_cards` (`job_card_no`)
