  `lead_date` date DEFAULT NULL,
  `end_date` date DEFAULT NULL,
  `in_time` datetime DEFAULT NULL,
  `out_time` datetime DEFAULT NULL,
  `actual_days` int DEFAULT NULL,
  `is_subcontract` tinyint(1) DEFAULT '0',
  `vendor_name` varchar(255) DEFAULT NULL,
  `subcontract_lead_days` int DEFAULT '0',
  `subcontract_start_date` date DEFAULT NULL,
  `subcontract_expected_date` date DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `job_card_no` (`job_card_no`),
  CONSTRAINT `job_card_process_days_ibfk_1` FOREIGN KEY (`job_card_no`) REFERENCES `job_cards` (`job_card_no`)
) ENGINE=InnoDB AUTO_INCREMENT=2199 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
