--
-- Table structure for table `job_cards`
--

DROP TABLE IF EXISTS `job_cards`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `job_cards` (
  `id` int NOT NULL AUTO_INCREMENT,
  `job_card_no` varchar(50) NOT NULL,
  `so_no` varchar(50) DEFAULT NULL,
  `customer_name` varchar(255) DEFAULT NULL,
  `work_order_no` varchar(50) DEFAULT NULL,
  `parent_code` varchar(50) DEFAULT NULL,
  `so_date` date DEFAULT NULL,
  `job_card_date` date DEFAULT NULL,
  `work_order_date` date DEFAULT NULL,
  `child_code` varchar(100) DEFAULT NULL,
  `final_status` varchar(50) DEFAULT 'Pending',
  `erp_status` varchar(50) DEFAULT 'Open',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `job_card_no` (`job_card_no`),
  KEY `idx_final_status` (`final_status`),
  KEY `idx_so_date` (`so_date`)
) ENGINE=InnoDB AUTO_INCREMENT=2641 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

