CREATE TABLE `revoke_log` (
  `id` int NOT NULL AUTO_INCREMENT,
  `job_card_no` varchar(50) NOT NULL,
  `item_name` varchar(255) NOT NULL,
  `from_process` varchar(100) NOT NULL COMMENT 'Process where revoke happened (e.g. R/Turning)',
  `to_process` varchar(100) NOT NULL COMMENT 'Immediate previous process for rework (e.g. Cutting)',
  `revoke_qty` int NOT NULL DEFAULT '0',
  `passed_qty` int DEFAULT NULL COMMENT 'Filled when revoke is completed',
  `rejected_qty` int DEFAULT NULL COMMENT 'If some fail even after rework',
  `remarks` text,
  `status` enum('Open','Completed') NOT NULL DEFAULT 'Open',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `completed_at` datetime DEFAULT NULL,
  `completed_by` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_revoke_job` (`job_card_no`),
  KEY `idx_revoke_status` (`status`),
  KEY `idx_revoke_job_status` (`job_card_no`,`status`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
