  `item_name` varchar(255) NOT NULL,
  `process_name` varchar(100) NOT NULL,
  `process_order` int NOT NULL COMMENT '1=first rework stage, 2=second, etc.',
  `lead_days` int DEFAULT '0',
  `in_time` datetime DEFAULT NULL,
  `out_time` datetime DEFAULT NULL,
  `actual_days` int DEFAULT NULL,
  `is_completed` tinyint(1) DEFAULT '0',
  `is_final` tinyint(1) DEFAULT '0' COMMENT '1 = last stage before rejoining main flow',
  `merged_to_main` tinyint(1) DEFAULT '0' COMMENT '1 = pieces rejoined main flow',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_rpd_revoke` (`revoke_id`),
  KEY `idx_rpd_job` (`job_card_no`),
  KEY `idx_rpd_completed` (`is_completed`),
  CONSTRAINT `revoke_process_days_ibfk_1` FOREIGN KEY (`revoke_id`) REFERENCES `revoke_log` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
